              <div>
                <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Estimating Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  {Object.values(Platform).map(p => (
                    <button key={p} onClick={() => setState(prev => ({ ...prev, platform: p }))} className={`py-4 rounded-2xl border-2 font-black text-xs uppercase tracking-widest transition-all ${state.platform === p ? 'border-indigo-600 dark:border-indigo-400 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 shadow-md' : 'border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-400 dark:text-slate-500 hover:border-slate-200 dark:hover:border-slate-700'}`}>{p}</button>
