    }

    if (step === 2) {
      const currentCategory = CATEGORIZED_ROOMS.find(c => c.title === activeRoomCategory) || CATEGORIZED_ROOMS[0];
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 p-8 animate-in fade-in">
          <div className="flex flex-col xl:flex-row items-start justify-between mb-10 gap-10">
            <div className="w-full xl:w-2/3 space-y-6">
               <h2 className="text-xl font-black flex items-center gap-2 text-slate-800 dark:text-slate-100"><LayoutGrid className="text-indigo-600 dark:text-indigo-400" /> Forensic Structural Zones</h2>

               <div className="flex gap-2 overflow-x-auto pb-4 no-scrollbar">
                  {CATEGORIZED_ROOMS.map(cat => (
                    <button 
                      key={cat.title} 
                      onClick={() => setActiveRoomCategory(cat.title)}
                      className={`px-4 py-3 rounded-2xl flex items-center gap-3 whitespace-nowrap transition-all border font-black text-[10px] uppercase tracking-widest ${activeRoomCategory === cat.title ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100 dark:shadow-none' : 'bg-slate-50 dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-slate-100 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-700'}`}
                    >
                      <cat.icon size={16} />
                      {cat.title}
                    </button>
