               </div>

               <div className="bg-slate-50/50 dark:bg-slate-800/30 p-8 rounded-[2rem] border border-slate-100 dark:border-slate-700/50">
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3">
                    {currentCategory.labels.map(label => (
                      <button 
                        key={label} 
                        onClick={() => addRoom(label, 'Room')} 
                        className="px-4 py-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 hover:border-indigo-400 dark:hover:border-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 text-slate-600 dark:text-slate-300 hover:text-indigo-600 dark:hover:text-indigo-400 rounded-xl text-[10px] font-black uppercase tracking-tight transition-all shadow-sm"
                      >
                        {label}
                      </button>
                    ))}
                  </div>
               </div>
            </div>

            <div className="w-full xl:w-1/3 space-y-6">
               <h3 className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest px-2">Exterior Elevation Face</h3>
               <div className="grid grid-cols-2 gap-3">
                 {EXTERIOR_LABELS.map(label => (
                   <button key={label} onClick={() => addRoom(label, 'Exterior Face')} className="px-4 py-4 bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400 hover:bg-amber-100 dark:hover:bg-amber-900/30 rounded-2xl text-[10px] font-black uppercase tracking-tight transition-all border border-amber-100 dark:border-amber-900/40 text-left flex flex-col gap-2">
                     <Camera size={16} />
                     {label}
                   </button>
                 ))}
               </div>
            </div>
          </div>

          <div className="border-t border-slate-100 dark:border-slate-800 pt-10">
            <h3 className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-6 px-2">Active Claim Zones ({state.rooms.length})</h3>
            {state.rooms.length === 0 ? (
              <div className="h-64 flex flex-col items-center justify-center border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl text-slate-300 dark:text-slate-700">
                <Building2 size={48} className="mb-4" />
                <p className="font-black text-xs uppercase tracking-widest">Select structural labels above to begin scoping</p>
