    }
    return null;
  };

  const renderInvestigationFlow = () => {
    if (step === 1) {
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl shadow-slate-200/50 dark:shadow-none border border-slate-200 dark:border-slate-800 p-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
