                      <input 
                        autoFocus 
                        type="text" 
                        placeholder="Type carrier name..." 
                        className="w-full px-4 py-2 text-sm bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 rounded-xl outline-none" 
                        value={state.carrier} 
                        onChange={e => setState(p => ({ ...p, carrier: e.target.value }))} 
                        onKeyDown={(e) => e.key === 'Enter' && selectCarrier(state.carrier)}
                      />
                    </div>
                    <div className="max-h-64 overflow-y-auto p-2">
                       {carrierFavorites.length > 0 && (
                         <div className="mb-2">
                            <p className="px-3 py-1 text-[9px] font-black text-slate-400 uppercase tracking-widest">Favorites</p>
                            {carrierFavorites.map(fav => (
                              <div key={fav} className="group flex items-center justify-between px-3 py-2 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-xl cursor-pointer" onClick={() => selectCarrier(fav)}>
                                <div className="flex items-center gap-3"><Star className="text-amber-400 fill-amber-400" size={12} /><span className="text-sm font-bold text-slate-700 dark:text-slate-200">{fav}</span></div>
                              </div>
                            ))}
                         </div>
                       )}
                       <div>
                         <p className="px-3 py-1 text-[9px] font-black text-slate-400 uppercase tracking-widest">Recent</p>
                         {carrierHistory.map(hist => (
                          <div key={hist} className="group flex items-center justify-between px-3 py-2 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl cursor-pointer" onClick={() => selectCarrier(hist)}>
                            <div className="flex items-center gap-3 text-slate-500 dark:text-slate-400"><History size={12} /><span className="text-sm font-medium">{hist}</span></div>
                            <button onClick={(e) => toggleFavorite(e, hist)} className="opacity-0 group-hover:opacity-100 p-1"><Star size={12} className="text-slate-300" /></button>
                          </div>
                         ))}
                       </div>
                    </div>
                  </div>
                )}
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Estimating Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  {Object.values(Platform).map(p => (
                    <button key={p} onClick={() => setState(prev => ({ ...prev, platform: p }))} className={`py-4 rounded-2xl border-2 font-black text-xs uppercase tracking-widest transition-all ${state.platform === p ? 'border-indigo-600 dark:border-indigo-400 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 shadow-md' : 'border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-400 dark:text-slate-500 hover:border-slate-200 dark:hover:border-slate-700'}`}>{p}</button>
                  ))}
                </div>
              </div>

              {fetchedGuidelines && (
                <div className="p-6 bg-slate-50 dark:bg-slate-800/30 rounded-3xl border border-slate-100 dark:border-slate-800 space-y-3">
                  <h4 className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest flex items-center gap-2"><ShieldCheck size={14}/> Active Guidelines</h4>
                  <div className="text-[11px] text-slate-600 dark:text-slate-400 leading-relaxed max-h-40 overflow-y-auto custom-scrollbar italic">
                    {fetchedGuidelines}
