                </div>
              )}
              {guidelinesLoading && (
                <div className="flex items-center gap-3 p-6 bg-indigo-50 dark:bg-indigo-900/10 rounded-3xl border border-indigo-100 dark:border-indigo-900/20 text-indigo-600 dark:text-indigo-400">
                   <Loader2 className="animate-spin" size={20} />
                   <p className="text-[10px] font-black uppercase tracking-widest">Consulting Search Grounding...</p>
                </div>
              )}
            </div>
            <div className="space-y-4">
              <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Claim Scope Synopsis</label>
