    }

    if (step === 2) {
      const currentCategory = CATEGORIZED_ROOMS.find(c => c.title === activeRoomCategory) || CATEGORIZED_ROOMS[0];
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 p-6 md:p-8 animate-in fade-in max-w-7xl mx-auto">
          <div className="flex flex-col xl:flex-row items-start justify-between mb-10 gap-10">
            <div className="w-full xl:w-2/3 space-y-8">
               <h2 className="text-xl font-black flex items-center gap-2 text-slate-800 dark:text-slate-100 px-2"><LayoutGrid className="text-indigo-600 dark:text-indigo-400" /> Forensic Structural Zones</h2>

               <div className="relative group">
                  <div className="flex gap-2 overflow-x-auto pb-4 px-2 no-scrollbar scroll-smooth">
                    {CATEGORIZED_ROOMS.map(cat => (
                      <button 
                        key={cat.title} 
                        onClick={() => setActiveRoomCategory(cat.title)}
                        className={`px-5 py-3.5 rounded-2xl flex items-center gap-3 whitespace-nowrap transition-all border font-black text-[11px] uppercase tracking-widest shrink-0 ${activeRoomCategory === cat.title ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100 dark:shadow-none' : 'bg-slate-50 dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-slate-100 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-700'}`}
                      >
                        <cat.icon size={16} />
                        {cat.title}
                      </button>
                    ))}
                  </div>
                  <div className="absolute right-0 top-0 bottom-4 w-12 bg-gradient-to-l from-white dark:from-slate-900 to-transparent pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity" />
               </div>

               <div className="bg-slate-50/50 dark:bg-slate-800/30 p-6 md:p-10 rounded-[2.5rem] border border-slate-100 dark:border-slate-700/50">
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {currentCategory.labels.map(label => (
                      <button 
                        key={label} 
                        onClick={() => addRoom(label, 'Room')} 
                        className="px-6 py-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 hover:border-indigo-400 dark:hover:border-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 text-slate-700 dark:text-slate-300 hover:text-indigo-600 dark:hover:text-indigo-400 rounded-2xl text-[11px] font-black uppercase tracking-wide transition-all shadow-sm flex items-center justify-between min-h-[3.5rem] text-left leading-tight"
                      >
                        <span className="max-w-[85%]">{label}</span>
                        <Plus size={14} className="opacity-40" />
                      </button>
                    ))}
                  </div>
               </div>
            </div>

            <div className="w-full xl:w-1/3 space-y-8">
               <h3 className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest px-2">Exterior Elevation Face</h3>
               <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                 {EXTERIOR_LABELS.map(label => (
                   <button key={label} onClick={() => addRoom(label, 'Exterior Face')} className="px-6 py-5 bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400 hover:bg-amber-100 dark:hover:bg-amber-900/30 rounded-[1.5rem] text-[11px] font-black uppercase tracking-wide transition-all border border-amber-100 dark:border-amber-900/40 text-left flex flex-col gap-3 min-h-[5rem] shadow-sm">
                     <Camera size={20} />
                     <span>{label}</span>
                   </button>
                 ))}
               </div>
            </div>
          </div>

          <div className="border-t border-slate-100 dark:border-slate-800 pt-10">
            <h3 className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-6 px-2 flex items-center gap-2">
               Active Claim Zones <span className="bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 px-2 py-0.5 rounded-full text-[10px]">{state.rooms.length}</span>
            </h3>
            {state.rooms.length === 0 ? (
              <div className="h-64 flex flex-col items-center justify-center border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl text-slate-300 dark:text-slate-700 bg-slate-50/20 dark:bg-slate-900/20">
                <Building2 size={48} className="mb-4 opacity-20" />
                <p className="font-black text-xs uppercase tracking-widest text-slate-400">Select structural labels above to begin scoping</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 mb-8">
                {state.rooms.map(room => (
                  <div key={room.id} className="p-5 border border-slate-100 dark:border-slate-800 rounded-2xl bg-white dark:bg-slate-900 shadow-sm flex items-center justify-between group hover:border-indigo-200 dark:hover:border-indigo-900/50 transition-all animate-in">
                    <div className="flex items-center gap-4 min-w-0">
                      <div className={`p-3 rounded-xl shrink-0 ${room.type === 'Room' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400'}`}>{room.type === 'Room' ? <Building2 size={18} /> : <Camera size={18} />}</div>
                      <div className="min-w-0">
                        <input className="font-black text-slate-800 dark:text-slate-100 focus:outline-none text-[13px] bg-transparent w-full truncate" value={room.name} onChange={(e) => setState(p => ({ ...p, rooms: p.rooms.map(r => r.id === room.id ? { ...r, name: e.target.value } : r) }))} />
