                      >
                        <cat.icon size={14} />
                        {cat.title}
                      </button>
                    ))}
                  </div>
                  <div className="absolute right-0 top-0 bottom-4 w-10 bg-gradient-to-l from-white dark:from-slate-900 to-transparent pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity" />
               </div>

               {/* Room Label Selection Grid */}
               <div className="bg-slate-50/50 dark:bg-slate-800/30 p-6 rounded-[2.5rem] border border-slate-100 dark:border-slate-700/50">
