                  </div>
               </div>
            </div>

            {/* Elevation Faces Sidebar */}
            <div className="w-full xl:w-[320px] shrink-0 space-y-6">
               <h3 className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest px-1">Elevation Faces</h3>
               <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-1 gap-3">
                 {EXTERIOR_LABELS.map(label => (
                   <button key={label} onClick={() => addRoom(label, 'Exterior Face')} className="px-5 py-5 bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400 hover:bg-amber-100 dark:hover:bg-amber-900/30 rounded-2xl text-[10px] font-black uppercase tracking-wide transition-all border border-amber-100 dark:border-amber-900/40 text-left flex flex-row items-center gap-4 min-h-[4.5rem] shadow-sm">
                     <div className="p-2.5 bg-white/50 dark:bg-black/20 rounded-xl shadow-inner shrink-0">
                       <Camera size={18} />
