               Active Forensic Zones <span className="bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 px-2.5 py-0.5 rounded-full text-[10px] font-black">{state.rooms.length}</span>
            </h3>
            {state.rooms.length === 0 ? (
              <div className="h-48 flex flex-col items-center justify-center border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl text-slate-300 dark:text-slate-700 bg-slate-50/20 dark:bg-slate-900/10">
                <Building2 size={32} className="mb-4 opacity-10" />
                <p className="font-black text-[10px] uppercase tracking-[0.2em] text-slate-400/80">Select structural labels above to scope</p>
