                    <button onClick={() => setState(p => ({ ...p, rooms: p.rooms.filter(r => r.id !== room.id) }))} className="p-2 text-slate-200 dark:text-slate-700 hover:text-red-500 dark:hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all shrink-0"><Trash2 size={14} /></button>
