          <div className="mt-12 flex justify-between border-t border-slate-50 dark:border-slate-800 pt-8">
            <button onClick={() => setStep(1)} className="px-8 py-3 text-slate-400 dark:text-slate-500 font-black text-xs uppercase hover:text-slate-600 dark:hover:text-slate-300 transition-all">Back</button>
