    }

    if (step === 2) {
      const currentCategory = CATEGORIZED_ROOMS.find(c => c.title === activeRoomCategory) || CATEGORIZED_ROOMS[0];
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 p-6 md:p-8 animate-in fade-in max-w-6xl mx-auto overflow-hidden">
