];

const EXTERIOR_LABELS = [
  'Front Elevation', 'Rear Elevation', 'Left Elevation', 
  'Right Elevation', 'Roof', 'Fence', 'Detached Structure'
];

interface SavedGuideline {
  id: string;
  carrier: string;
  content: string;
  timestamp: number;
}

const EvidenceTypeIcon = ({ type }: { type: EvidenceType }) => {
  switch (type) {
    case 'Photo': return <ImageIcon size={16} />;
    case 'PDF Package': return <Files size={16} />;
    case 'Measurement Report': return <Map size={16} />;
    case 'Scope Sheet': return <ClipboardCheck size={16} />;
    default: return <FileText size={16} />;
  }
};

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.THEME);
    return saved === 'dark' || (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [state, setState] = useState<EstimationState>({
    mode: AppMode.DASHBOARD,
    carrier: '',
    synopsis: '',
    platform: Platform.XACTIMATE,
    rooms: [],
    evidence: [],
    lineItems: [],
    isAnalyzing: false,
    analysisComplete: false,
    platformA: Platform.XACTIMATE,
    platformB: Platform.SYMBILITY_COTALITY
  });

  const [step, setStep] = useState(1);
  const [guidelinesLoading, setGuidelinesLoading] = useState(false);
  const [fetchedGuidelines, setFetchedGuidelines] = useState('');
  const [carrierHistory, setCarrierHistory] = useState<string[]>([]);
  const [carrierFavorites, setCarrierFavorites] = useState<string[]>([]);
  const [savedGuidelines, setSavedGuidelines] = useState<SavedGuideline[]>([]);
  const [isCarrierDropdownOpen, setIsCarrierDropdownOpen] = useState(false);
  const [activeRoomCategory, setActiveRoomCategory] = useState(CATEGORIZED_ROOMS[0].title);

  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraRoomId, setCameraRoomId] = useState<string | undefined>(undefined);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem(STORAGE_KEYS.THEME, 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem(STORAGE_KEYS.THEME, 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const history = JSON.parse(localStorage.getItem(STORAGE_KEYS.HISTORY) || '[]');
    const favorites = JSON.parse(localStorage.getItem(STORAGE_KEYS.FAVORITES) || '[]');
    const guidelines = JSON.parse(localStorage.getItem(STORAGE_KEYS.SAVED_GUIDELINES) || '[]');
    setCarrierHistory(history);
    setCarrierFavorites(favorites);
    setSavedGuidelines(guidelines);

    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsCarrierDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleModeToggle = (mode: AppMode) => {
    setState(prev => ({ 
      ...prev, 
      mode, 
      analysisComplete: false, 
      isAnalyzing: false, 
      evidence: [], 
      lineItems: [], 
      comparisonResult: undefined,
      carrier: mode === AppMode.DASHBOARD ? '' : prev.carrier
    }));
    setStep(1);
    setFetchedGuidelines('');
  };

  const saveCurrentGuideline = () => {
    if (!state.carrier || !fetchedGuidelines) return;
    const newGuideline: SavedGuideline = {
      id: crypto.randomUUID(),
      carrier: state.carrier,
      content: fetchedGuidelines,
      timestamp: Date.now()
    };
    const updated = [newGuideline, ...savedGuidelines];
    setSavedGuidelines(updated);
    localStorage.setItem(STORAGE_KEYS.SAVED_GUIDELINES, JSON.stringify(updated));
    alert(`${state.carrier} guidelines saved to library.`);
  };

  const deleteSavedGuideline = (id: string) => {
    const updated = savedGuidelines.filter(g => g.id !== id);
    setSavedGuidelines(updated);
    localStorage.setItem(STORAGE_KEYS.SAVED_GUIDELINES, JSON.stringify(updated));
  };

  const startCamera = async (roomId?: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        streamRef.current = stream;
        setCameraRoomId(roomId);
        setIsCameraOpen(true);
      }
    } catch (err) {
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
    setCameraRoomId(undefined);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg');
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId: cameraRoomId,
          type: 'Photo',
          base64,
          mimeType: 'image/jpeg',
          fileName: `capture_${Date.now()}.jpg`
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
        stopCamera();
      }
    }
  };

  const handleComparisonFileUpload = (side: 'A' | 'B', file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = e.target?.result as string;
      const evidence: EvidenceItem = {
        id: crypto.randomUUID(),
        type: 'Estimate File',
        base64,
        mimeType: file.type || 'application/octet-stream',
        fileName: file.name
      };
      setState(prev => ({ ...prev, [side === 'A' ? 'fileA' : 'fileB']: evidence }));
    };
    reader.readAsDataURL(file);
  };

  const runComparison = async () => {
    if (!state.fileA || !state.fileB) {
      alert("Please upload both Estimate A and Estimate B before running comparison.");
      return;
    }
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const result = await compareEstimates(state.fileA, state.fileB, state.platformA, state.platformB);
      setState(prev => ({ ...prev, comparisonResult: result, isAnalyzing: false, analysisComplete: true }));
      setStep(3);
    } catch (err) {
      alert("Comparison analysis failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const selectCarrier = (carrierName: string) => {
    setState(p => ({ ...p, carrier: carrierName }));
    setIsCarrierDropdownOpen(false);
    const newHistory = [carrierName, ...carrierHistory.filter(h => h !== carrierName)].slice(0, 10);
    setCarrierHistory(newHistory);
    localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(newHistory));

    fetchGuidelines(carrierName);
  };

  const fetchGuidelines = async (carrierName: string) => {
    setGuidelinesLoading(true);
    try {
      const res = await fetchCarrierGuidelines(carrierName);
      setFetchedGuidelines(res);
    } catch (e) {
      console.error(e);
    } finally {
      setGuidelinesLoading(false);
    }
  };

  const toggleFavorite = (e: React.MouseEvent, carrierName: string) => {
    e.stopPropagation();
    let newFavs: string[];
    if (carrierFavorites.includes(carrierName)) {
      newFavs = carrierFavorites.filter(f => f !== carrierName);
    } else {
      newFavs = [...carrierFavorites, carrierName];
    }
    setCarrierFavorites(newFavs);
    localStorage.setItem(STORAGE_KEYS.FAVORITES, JSON.stringify(newFavs));
  };

  const addRoom = (baseLabel: string, type: 'Room' | 'Exterior Face') => {
    const existingSameLabels = state.rooms.filter(r => r.name.startsWith(baseLabel));
    let nextName = baseLabel;

    if (existingSameLabels.length > 0) {
      let maxNum = 0;
      existingSameLabels.forEach(r => {
        const match = r.name.match(new RegExp(`^${baseLabel}\\s*(\\d+)$`));
        if (match) {
          const num = parseInt(match[1]);
          if (num > maxNum) maxNum = num;
        } else if (r.name === baseLabel) {
          if (maxNum === 0) maxNum = 1;
        }
      });
      nextName = `${baseLabel} ${maxNum + 1}`;
    }

    const newRoom: Room = { id: crypto.randomUUID(), name: nextName, type };
    setState(prev => ({ ...prev, rooms: [...prev.rooms, newRoom] }));
  };

  const handleEvidenceUpload = (type: EvidenceType, roomId?: string, files?: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newItem: EvidenceItem = {
          id: crypto.randomUUID(),
          roomId,
          type,
          base64: e.target?.result as string,
          mimeType: file.type,
          fileName: file.name
        };
        setState(prev => ({ ...prev, evidence: [...prev.evidence, newItem] }));
      };
      reader.readAsDataURL(file);
    });
  };

  const runInvestigationAnalysis = async () => {
    const hasDetailedSynopsis = (state.synopsis?.length || 0) > 100;

    if (state.evidence.length === 0 && !hasDetailedSynopsis) {
      alert("Please provide either a detailed synopsis or upload evidence (photos/reports) before running analysis.");
      return;
    }

    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const roomMap = state.rooms.reduce((acc, r) => ({ ...acc, [r.id]: r.name }), {});
      const result = await analyzeDamage(
        state.platform, 
        state.carrier || "Unknown Carrier", 
        state.synopsis || "No synopsis provided", 
        fetchedGuidelines || state.customGuidelines || "Standard industry rules", 
        state.evidence, 
        roomMap
      );
      setState(prev => ({ 
        ...prev, 
        lineItems: result.lineItems, 
        evidence: result.labeledEvidence, 
        isAnalyzing: false, 
        analysisComplete: true 
      }));
      setStep(4);
    } catch (err) {
      alert("Investigation failed.");
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const renderDashboard = () => {
    return (
      <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
        <div className="text-center space-y-4">
          <h2 className="text-4xl font-black text-slate-800 dark:text-slate-100 tracking-tight">Enterprise Claims Dashboard</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium max-w-xl mx-auto">Select a workflow to begin. AdjusterAI automates forensic scoping and estimate auditing for insurance professionals.</p>
        </div>

        <div className="grid md:grid-cols-2 gap-8 max-w-4xl mx-auto">
          <button 
            onClick={() => handleModeToggle(AppMode.INVESTIGATION)}
            className="group relative bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl hover:shadow-2xl hover:border-indigo-500 dark:hover:border-indigo-400 transition-all text-left overflow-hidden"
          >
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
              <ClipboardCheck size={120} className="text-indigo-600 dark:text-indigo-400" />
            </div>
            <div className="relative z-10 space-y-6">
              <div className="bg-indigo-50 dark:bg-indigo-900/30 w-16 h-16 rounded-2xl flex items-center justify-center text-indigo-600 dark:text-indigo-400">
                <Search size={32} />
              </div>
              <div>
                <h3 className="text-2xl font-black text-slate-800 dark:text-slate-100">Claim Investigation</h3>
                <p className="text-slate-500 dark:text-slate-400 font-medium mt-2">Generate line items from site evidence and carrier-specific guidelines.</p>
              </div>
              <div className="flex items-center text-indigo-600 dark:text-indigo-400 font-black text-xs uppercase tracking-widest gap-2">
                Launch Workflow <ChevronRight size={16} />
              </div>
            </div>
          </button>

          <button 
            onClick={() => handleModeToggle(AppMode.COMPARISON)}
            className="group relative bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl hover:shadow-2xl hover:border-amber-500 dark:hover:border-amber-400 transition-all text-left overflow-hidden"
          >
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
              <ArrowRightLeft size={120} className="text-amber-600 dark:text-amber-400" />
            </div>
            <div className="relative z-10 space-y-6">
              <div className="bg-amber-50 dark:bg-amber-900/30 w-16 h-16 rounded-2xl flex items-center justify-center text-amber-600 dark:text-amber-400">
                <ArrowRightLeft size={32} />
              </div>
              <div>
                <h3 className="text-2xl font-black text-slate-800 dark:text-slate-100">Estimate Comparison</h3>
                <p className="text-slate-500 dark:text-slate-400 font-medium mt-2">Identify variances between multi-platform estimates and audit quantity deltas.</p>
              </div>
              <div className="flex items-center text-amber-600 dark:text-amber-400 font-black text-xs uppercase tracking-widest gap-2">
                Launch Workflow <ChevronRight size={16} />
              </div>
            </div>
          </button>
        </div>

        <div className="max-w-4xl mx-auto space-y-6">
          <div className="flex items-center justify-between px-4">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
              <BookOpen size={16} /> Carrier Documentation Library
            </h3>
          </div>

          {savedGuidelines.length === 0 ? (
            <div className="bg-slate-50 dark:bg-slate-900/50 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-3xl p-12 text-center space-y-3">
              <Files className="text-slate-300 dark:text-slate-700 mx-auto" size={48} />
              <p className="text-slate-400 dark:text-slate-600 font-black text-xs uppercase tracking-widest">No saved carrier documentation found.</p>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {savedGuidelines.map(g => (
                <div key={g.id} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl p-6 shadow-sm hover:shadow-md transition-all group">
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-indigo-50 dark:bg-indigo-900/30 p-2 rounded-xl text-indigo-600 dark:text-indigo-400">
                      <Shield size={20} />
                    </div>
                    <button 
                      onClick={() => deleteSavedGuideline(g.id)}
                      className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                  <h4 className="font-black text-slate-800 dark:text-slate-100 truncate">{g.carrier} Guidelines</h4>
                  <p className="text-[10px] font-black text-slate-400 uppercase mt-1">Archived {new Date(g.timestamp).toLocaleDateString()}</p>
                  <button 
                    onClick={() => {
                      setState(prev => ({ ...prev, mode: AppMode.INVESTIGATION, carrier: g.carrier }));
                      setFetchedGuidelines(g.content);
                      setStep(1);
                    }}
                    className="w-full mt-6 py-2.5 bg-slate-50 dark:bg-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-600 dark:text-slate-400 hover:bg-indigo-600 hover:text-white transition-all"
                  >
                    Use Specifications
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderSettings = () => {
    return (
      <div className="max-w-3xl mx-auto space-y-10 animate-in fade-in">
        <div className="flex items-center gap-4 mb-10">
          <button onClick={() => handleModeToggle(AppMode.DASHBOARD)} className="p-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-all">
            <ChevronLeft size={20} />
          </button>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">App Settings</h2>
        </div>

        <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] p-10 space-y-12 shadow-xl">
          <section className="space-y-6">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Display & Theme</h3>
            <div className="flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-800/50 rounded-3xl border border-slate-100 dark:border-slate-800">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-white dark:bg-slate-900 rounded-2xl shadow-sm text-amber-500">
                  {isDarkMode ? <Moon size={24} /> : <Sun size={24} />}
                </div>
                <div>
                  <p className="font-black text-slate-800 dark:text-slate-100">Dark Mode</p>
                  <p className="text-xs text-slate-500 font-medium">Reduce eye strain in low-light environments</p>
                </div>
              </div>
              <button 
                onClick={toggleTheme}
                className={`relative w-16 h-8 rounded-full transition-colors ${isDarkMode ? 'bg-indigo-600' : 'bg-slate-200'}`}
              >
                <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full transition-transform ${isDarkMode ? 'translate-x-8' : ''}`} />
              </button>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Gemini Engine</h3>
            <div className="space-y-4">
              <div className="flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-800/50 rounded-3xl border border-slate-100 dark:border-slate-800">
                <div>
                  <p className="font-black text-slate-800 dark:text-slate-100">Forensic Reasoning Model</p>
                  <p className="text-xs text-slate-500 font-medium">Gemini 3.0 Pro Active</p>
                </div>
                <div className="flex items-center gap-2 px-3 py-1 bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 rounded-full text-[10px] font-black uppercase">
                  <Zap size={10} fill="currentColor" /> Live
                </div>
              </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Data Management</h3>
            <button 
              onClick={() => {
                if(confirm("Clear all application state and cached guidelines?")) {
                  localStorage.clear();
                  window.location.reload();
                }
              }}
              className="w-full py-4 px-6 border border-red-200 dark:border-red-900/50 text-red-600 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-red-50 dark:hover:bg-red-900/10 transition-all flex items-center justify-center gap-2"
            >
              <Trash2 size={16} /> Reset All Application History
            </button>
          </section>
        </div>
      </div>
    );
  };

  const renderComparisonFlow = () => {
    if (step === 1) {
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl p-8 animate-in fade-in slide-in-from-bottom-2 duration-500 max-w-5xl mx-auto border border-slate-200 dark:border-slate-800">
          <div className="text-center mb-10">
            <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100 mb-2 flex items-center justify-center gap-3">
              <ArrowRightLeft className="text-indigo-600 dark:text-indigo-400" size={32} />
              Comparative Estimate Analysis
            </h2>
            <p className="text-slate-500 dark:text-slate-400 font-medium">Identify line item variances and financial discrepancies between platforms.</p>
          </div>

          <div className="grid md:grid-cols-2 gap-10 mb-10">
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Estimate A (Baseline)</label>
              </div>
              <div className="space-y-4">
                <select 
                  className="w-full px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm font-bold bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  value={state.platformA}
                  onChange={e => setState(p => ({ ...p, platformA: e.target.value as Platform }))}
                >
                  {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <label className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800 transition-all group relative overflow-hidden">
                  {state.fileA ? (
                    <div className="flex flex-col items-center gap-3 text-indigo-600 dark:text-indigo-400">
                      <div className="bg-indigo-100 dark:bg-indigo-900/30 p-4 rounded-full shadow-inner"><CheckCircle2 size={40} /></div>
                      <span className="text-sm font-black text-center px-4 truncate max-w-full text-slate-900 dark:text-slate-100">{state.fileA.fileName}</span>
                      <button onClick={(e) => {e.preventDefault(); setState(p => ({...p, fileA: undefined}))}} className="text-[10px] font-black uppercase tracking-widest text-red-500 hover:underline">Remove</button>
                    </div>
                  ) : (
                    <>
                      <Upload className="text-slate-300 dark:text-slate-600 group-hover:text-indigo-400 mb-4 transition-colors" size={48} />
                      <span className="text-sm font-black text-slate-400 dark:text-slate-500">Drop ESX, XML, CSV or PDF</span>
                    </>
                  )}
                  <input type="file" className="hidden" onChange={e => e.target.files?.[0] && handleComparisonFileUpload('A', e.target.files[0])} />
                </label>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Estimate B (Comparison)</label>
              </div>
              <div className="space-y-4">
                <select 
                  className="w-full px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm font-bold bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all"
                  value={state.platformB}
                  onChange={e => setState(p => ({ ...p, platformB: e.target.value as Platform }))}
                >
                  {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
