                  {CATEGORIZED_ROOMS.map(cat => (
                    <button 
                      key={cat.title} 
                      onClick={() => setActiveRoomCategory(cat.title)}
                      className={`px-5 py-3 rounded-2xl flex items-center gap-3 whitespace-nowrap transition-all border font-black text-[11px] uppercase tracking-wider shrink-0 ${activeRoomCategory === cat.title ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' : 'bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 border-slate-100 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-700'}`}
                    >
                      <cat.icon size={16} />
                      {cat.title}
                    </button>
                  ))}
                  <div className="min-w-[40px] h-1 shrink-0" /> {/* Edge spacer to prevent truncation */}
                </div>
                {/* Visual indicator for horizontal scrollability */}
                <div className="absolute top-0 right-0 bottom-0 w-12 bg-gradient-to-l from-white dark:from-slate-950 to-transparent pointer-events-none opacity-50" />
              </div>

              {/* Interior Room Selection Area */}
              <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 p-8 shadow-sm">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-sm font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                    <currentCategory.icon size={18} className="text-indigo-500" />
