                  </h3>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                  {currentCategory.labels.map(label => (
                    <button 
                      key={label} 
                      onClick={() => addRoom(label, 'Room')} 
                      className="group px-6 py-5 bg-slate-50 dark:bg-slate-800/40 border border-slate-100 dark:border-slate-700 hover:border-indigo-400 dark:hover:border-indigo-500 hover:bg-white dark:hover:bg-slate-800 text-slate-700 dark:text-slate-300 hover:text-indigo-600 dark:hover:text-indigo-400 rounded-2xl text-[12px] font-black uppercase tracking-wide transition-all shadow-sm flex items-center justify-between min-h-[4.5rem] text-left leading-tight"
                    >
                      <span className="max-w-[85%]">{label}</span>
                      <Plus size={16} className="opacity-0 group-hover:opacity-100 transition-opacity shrink-0" />
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Right Column: Elevations & Common Operatings */}
            <div className="lg:col-span-4 space-y-8">
              <div className="bg-amber-50/30 dark:bg-amber-900/10 rounded-[2.5rem] border border-amber-100/50 dark:border-amber-900/20 p-8 shadow-sm h-full">
                <h3 className="text-sm font-black text-amber-600 dark:text-amber-500 uppercase tracking-[0.2em] mb-8 flex items-center gap-2">
                  <Camera size={18} /> Exterior Elevations
                </h3>
                <div className="grid grid-cols-1 gap-3">
                  {EXTERIOR_LABELS.map(label => (
                    <button 
                      key={label} 
                      onClick={() => addRoom(label, 'Exterior Face')} 
                      className="group px-6 py-5 bg-white dark:bg-slate-900 border border-amber-100 dark:border-amber-900/30 hover:border-amber-500 text-amber-600 dark:text-amber-400 rounded-2xl text-[12px] font-black uppercase tracking-wide transition-all shadow-sm flex items-center gap-5 min-h-[5rem] text-left"
                    >
                      <div className="bg-amber-50 dark:bg-amber-900/50 p-3 rounded-xl shadow-inner group-hover:scale-110 transition-transform">
                        <Camera size={20} />
                      </div>
                      <span className="flex-1">{label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>

          {/* Active List Section */}
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 p-8 shadow-sm">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-sm font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] flex items-center gap-3">
                Current Forensic Scope <span className="bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 px-3 py-1 rounded-full text-xs font-bold">{state.rooms.length}</span>
              </h3>
            </div>
            {state.rooms.length === 0 ? (
              <div className="h-40 flex flex-col items-center justify-center border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl text-slate-300 dark:text-slate-700 bg-slate-50/20 dark:bg-slate-900/20">
                <Building2 size={40} className="mb-3 opacity-20" />
                <p className="font-black text-xs uppercase tracking-widest text-slate-400">Add structural zones from the selector above</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                {state.rooms.map(room => (
                  <div key={room.id} className="p-5 border border-slate-100 dark:border-slate-800 rounded-2xl bg-slate-50 dark:bg-slate-800/30 group hover:border-indigo-300 dark:hover:border-indigo-800 transition-all flex items-center justify-between">
                    <div className="flex items-center gap-4 min-w-0">
                      <div className={`p-3 rounded-xl shrink-0 ${room.type === 'Room' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400'}`}>
                        {room.type === 'Room' ? <Building2 size={18} /> : <Camera size={18} />}
                      </div>
                      <div className="min-w-0">
                        <input className="font-black text-slate-800 dark:text-slate-100 focus:outline-none text-[13px] bg-transparent w-full" value={room.name} onChange={(e) => setState(p => ({ ...p, rooms: p.rooms.map(r => r.id === room.id ? { ...r, name: e.target.value } : r) }))} />
                        <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase mt-0.5 tracking-tighter">{room.type}</p>
                      </div>
                    </div>
                    <button onClick={() => setState(p => ({ ...p, rooms: p.rooms.filter(r => r.id !== room.id) }))} className="p-2 text-slate-300 dark:text-slate-600 hover:text-red-500 transition-all opacity-0 group-hover:opacity-100">
                      <Trash2 size={18} />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Navigation */}
          <div className="flex justify-between items-center py-6 px-4">
            <button onClick={() => setStep(1)} className="px-8 py-4 text-slate-400 dark:text-slate-500 font-black text-xs uppercase tracking-[0.2em] hover:text-indigo-600 dark:hover:text-indigo-400 transition-all flex items-center gap-2">
              <ChevronLeft size={18} /> Previous Step
            </button>
            <button onClick={() => setStep(3)} className="bg-slate-900 dark:bg-slate-800 hover:bg-black dark:hover:bg-slate-700 text-white px-12 py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] flex items-center gap-4 transition-all shadow-2xl active:scale-95">
              Evidence Collection <ChevronRight size={18} />
            </button>
          </div>
