import React, { useState, useEffect, useRef } from 'react';
import { 
  Building2, 
  ClipboardCheck, 
  Camera, 
  FileText, 
  ChevronRight, 
  Plus, 
  Trash2, 
  Loader2, 
  CheckCircle2, 
  Download,
  AlertCircle,
  Droplets,
  Flame,
  Construction,
  Sparkles,
  Info,
  ShieldCheck,
  Star,
  History,
  Search,
  Upload,
  ChevronDown,
  X,
  FileSearch,
  Map,
  Files,
  ArrowRightLeft,
  TrendingDown,
  TrendingUp,
  Minus,
  LayoutGrid,
  Zap,
  Shield,
