                <div className="space-y-2">
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>A:</span><span>${res.summary.material.a.toLocaleString()}</span></div>
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>B:</span><span>${res.summary.material.b.toLocaleString()}</span></div>
                   <div className={`pt-2 border-t dark:border-slate-800 font-black text-lg ${res.summary.material.b - res.summary.material.a < 0 ? 'text-red-500' : 'text-green-500'}`}>{res.summary.material.b - res.summary.material.a > 0 ? '+' : ''}{(res.summary.material.b - res.summary.material.a).toLocaleString()}</div>
                </div>
             </div>
          </div>
          <div className="grid lg:grid-cols-3 gap-8">
