                        onChange={e => setState(p => ({ ...p, carrier: e.target.value }))} 
                        onKeyDown={(e) => e.key === 'Enter' && selectCarrier(state.carrier)}
                      />
                    </div>
                    <div className="max-h-64 overflow-y-auto p-2">
                       {carrierFavorites.length > 0 && (
                         <div className="mb-2">
                            <p className="px-3 py-1 text-[9px] font-black text-slate-400 uppercase tracking-widest">Favorites</p>
