              <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 p-8 shadow-sm min-h-[600px]">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-sm font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] flex items-center gap-3">
                    Active Forensic Scope <span className="bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 px-3 py-1 rounded-full text-xs font-bold">{state.rooms.length}</span>
                  </h3>
                  {state.rooms.length > 0 && (
                    <button 
                      onClick={() => setState(p => ({ ...p, rooms: [] }))}
                      className="text-[10px] font-black uppercase tracking-widest text-red-500 hover:text-red-600 flex items-center gap-1"
                    >
                      <Trash2 size={12} /> Clear All
                    </button>
                  )}
                </div>

                {state.rooms.length === 0 ? (
                  <div className="h-[400px] flex flex-col items-center justify-center border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl text-slate-300 dark:text-slate-700 bg-slate-50/20 dark:bg-slate-900/20 px-8 text-center">
                    <LayoutGrid size={48} className="mb-4 opacity-20" />
                    <h4 className="font-black text-lg text-slate-400 dark:text-slate-500 mb-2">No areas selected yet</h4>
                    <p className="text-xs font-medium text-slate-400 max-w-xs leading-relaxed">Choose room types from the list on the left to begin building your claim structure.</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {state.rooms.map(room => (
                      <div key={room.id} className="p-5 border border-slate-100 dark:border-slate-800 rounded-2xl bg-slate-50 dark:bg-slate-800/30 group hover:border-indigo-300 dark:hover:border-indigo-800 transition-all flex items-center justify-between animate-in fade-in zoom-in-95 duration-200">
                        <div className="flex items-center gap-4 min-w-0">
                          <div className={`p-3 rounded-xl shrink-0 ${room.type === 'Room' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400'}`}>
                            {room.type === 'Room' ? <Building2 size={18} /> : <Camera size={18} />}
                          </div>
                          <div className="min-w-0">
                            <input 
                              className="font-black text-slate-800 dark:text-slate-100 focus:outline-none text-[13px] bg-transparent w-full" 
                              value={room.name} 
                              onChange={(e) => setState(p => ({ ...p, rooms: p.rooms.map(r => r.id === room.id ? { ...r, name: e.target.value } : r) }))} 
                            />
                            <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase mt-0.5 tracking-tighter">{room.type === 'Room' ? 'Interior' : 'Exterior'}</p>
                          </div>
                        </div>
                        <button onClick={() => setState(p => ({ ...p, rooms: p.rooms.filter(r => r.id !== room.id) }))} className="p-2 text-slate-300 dark:text-slate-600 hover:text-red-500 transition-all opacity-0 group-hover:opacity-100">
                          <Trash2 size={18} />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Navigation */}
          <div className="flex justify-between items-center py-6 px-4">
            <button onClick={() => setStep(1)} className="px-8 py-4 text-slate-400 dark:text-slate-500 font-black text-xs uppercase tracking-[0.2em] hover:text-indigo-600 dark:hover:text-indigo-400 transition-all flex items-center gap-2">
              <ChevronLeft size={18} /> Previous Step
            </button>
            <button 
              onClick={() => setStep(3)} 
              disabled={state.rooms.length === 0}
              className={`px-12 py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] flex items-center gap-4 transition-all shadow-2xl active:scale-95 ${state.rooms.length > 0 ? 'bg-slate-900 dark:bg-slate-800 hover:bg-black dark:hover:bg-slate-700 text-white' : 'bg-slate-100 dark:bg-slate-900 text-slate-400 cursor-not-allowed'}`}
            >
              Evidence Collection <ChevronRight size={18} />
            </button>
          </div>
        </div>
      );
    }

    if (step === 3) {
      return (
        <div className="space-y-10 animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 p-8">
            <div className="flex items-center justify-between mb-10">
              <div><h2 className="text-xl font-black flex items-center gap-2 text-slate-800 dark:text-slate-100"><Files className="text-indigo-600 dark:text-indigo-400" /> Evidence & Documents</h2></div>
              <div className="flex gap-3">
                 <label className="cursor-pointer bg-slate-900 dark:bg-slate-800 text-white px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-lg hover:bg-black dark:hover:bg-slate-700">
                    <Map size={14} /> Measurement Report
                    <input type="file" multiple accept=".pdf,.jpg,.png" className="hidden" onChange={(e) => handleEvidenceUpload('Measurement Report', undefined, e.target.files)} />
                 </label>
                 <label className="cursor-pointer bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-900 dark:text-slate-100 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-md">
                    <Files size={14} /> Scope PDF
                    <input type="file" multiple accept=".pdf" className="hidden" onChange={(e) => handleEvidenceUpload('PDF Package', undefined, e.target.files)} />
                 </label>
              </div>
            </div>

            <div className="space-y-12">
               {state.evidence.some(e => !e.roomId) && (
                 <div className="bg-slate-50/50 dark:bg-slate-800/30 rounded-3xl p-6 border border-slate-100 dark:border-slate-800 border-dashed grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-6">
                    {state.evidence.filter(e => !e.roomId).map(doc => (
                      <div key={doc.id} className="relative aspect-[3/4] rounded-2xl overflow-hidden border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 group p-4 flex flex-col items-center justify-center text-center shadow-sm hover:shadow-md transition-all">
                        <EvidenceTypeIcon type={doc.type} />
                        <span className="mt-2 text-[10px] font-bold text-slate-600 dark:text-slate-400 line-clamp-2 uppercase tracking-tighter">{doc.fileName}</span>
                        <button onClick={() => setState(p => ({ ...p, evidence: p.evidence.filter(ev => ev.id !== doc.id) }))} className="absolute -top-1 -right-1 p-2 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-all shadow-lg scale-75"><X size={16} /></button>
                      </div>
                    ))}
                 </div>
               )}

               <div className="space-y-10">
                  {state.rooms.map(room => (
                    <div key={room.id} className="pt-6 border-t border-slate-50 dark:border-slate-800">
                       <div className="flex items-center justify-between mb-6">
                          <h3 className="font-black text-slate-800 dark:text-slate-200 tracking-tight text-lg flex items-center gap-3"><div className="h-5 w-1 bg-indigo-500 rounded-full"></div>{room.name}</h3>
                          <div className="flex flex-wrap gap-2">
                            <button onClick={() => startCamera(room.id)} className="bg-indigo-600 dark:bg-indigo-500 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-md hover:bg-indigo-700 dark:hover:bg-indigo-400">
                              <Camera size={14} /> Take Photo
                            </button>
                            <label className="cursor-pointer bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-900 dark:text-slate-100 px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-sm">
                              <ImageIcon size={14} /> Add Photos
                              <input type="file" multiple accept="image/*" className="hidden" onChange={(e) => handleEvidenceUpload('Photo', room.id, e.target.files)} />
                            </label>
                          </div>
                       </div>
                       <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-6">
                          {state.evidence.filter(e => e.roomId === room.id).map(item => (
                            <div key={item.id} className="relative aspect-square rounded-2xl overflow-hidden border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 group shadow-sm">
                               {item.mimeType.includes('image') ? <img src={item.base64} alt="evidence" className="w-full h-full object-cover" /> : <div className="w-full h-full flex flex-col items-center justify-center p-4"><Files className="text-slate-300 dark:text-slate-600 mb-2" size={24} /><span className="text-[9px] font-black text-slate-400 dark:text-slate-500 text-center uppercase tracking-tighter">{item.fileName}</span></div>}
                               <button onClick={() => setState(p => ({ ...p, evidence: p.evidence.filter(ev => ev.id !== item.id) }))} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-all shadow-lg scale-75"><X size={12} /></button>
                            </div>
                          ))}
                       </div>
                    </div>
                  ))}
               </div>
            </div>

            <div className="mt-16 flex justify-between border-t border-slate-100 dark:border-slate-800 pt-10">
              <button onClick={() => setStep(2)} className="px-8 py-3 text-slate-400 dark:text-slate-500 font-black text-xs uppercase tracking-widest">Back</button>
              <button onClick={runInvestigationAnalysis} disabled={state.isAnalyzing} className="bg-indigo-600 dark:bg-indigo-500 hover:bg-indigo-700 dark:hover:bg-indigo-400 disabled:opacity-50 text-white px-12 py-5 rounded-3xl font-black text-sm uppercase flex items-center gap-4 transition-all shadow-2xl shadow-indigo-100 dark:shadow-indigo-900/20 active:scale-95">
                {state.isAnalyzing ? <><Loader2 className="animate-spin" size={20} /> Analyzing...</> : <><CheckCircle2 size={24} /> Generate Forensic Scope</>}
              </button>
            </div>
          </div>
        </div>
      );
    }

    if (step === 4 && state.analysisComplete) {
      return (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
          <div className="grid md:grid-cols-3 gap-8">
            <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-lg flex items-center gap-6">
              <div className="bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-2xl text-indigo-600 dark:text-indigo-400"><FileText size={28} /></div>
              <div><p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Line Items</p><h3 className="text-3xl font-black text-slate-800 dark:text-slate-100">{state.lineItems.length}</h3></div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-lg flex items-center gap-6">
              <div className="bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl text-amber-600 dark:text-amber-400"><Files size={28} /></div>
              <div><p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Evidence Analyzed</p><h3 className="text-3xl font-black text-slate-800 dark:text-slate-100">{state.evidence.length}</h3></div>
            </div>
          </div>

          <div className="grid lg:grid-cols-5 gap-10">
            <div className="lg:col-span-2 space-y-8">
               <h2 className="text-xl font-black px-4 text-slate-800 dark:text-slate-200 uppercase tracking-tight">Evidence Log</h2>
               <div className="space-y-8 max-h-[1200px] overflow-auto pr-6 custom-scrollbar">
                  {state.evidence.map(item => (
                    <div key={item.id} className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-xl overflow-hidden group">
                       <div className="relative aspect-video bg-slate-50 dark:bg-slate-800">
                          {item.mimeType.includes('image') ? <img src={item.base64} alt="Evidence" className="w-full h-full object-cover" /> : <div className="w-full h-full flex flex-col items-center justify-center"><FileSearch className="text-indigo-200 dark:text-slate-700" size={48} /></div>}
                          <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
                            <div className="px-4 py-1.5 bg-black/70 backdrop-blur rounded-xl text-[9px] font-black text-white uppercase tracking-widest">{state.rooms.find(r => r.id === item.roomId)?.name || "Global Document"}</div>
                          </div>
                       </div>
                       <div className="p-6 space-y-4">
                          <p className="text-sm text-slate-700 dark:text-slate-300 leading-relaxed font-bold tracking-tight">{item.detectedDamage?.observations}</p>
                          <div className="pt-4 border-t border-slate-50 dark:border-slate-800"><p className="text-sm text-indigo-900 dark:text-indigo-400 italic font-black">{item.label}</p></div>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
            <div className="lg:col-span-3">
               <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-2xl border border-slate-200 dark:border-slate-800 flex flex-col h-full overflow-hidden">
                  <div className="p-8 border-b dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20 flex items-center justify-between">
                     <h2 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase">Generated Scope</h2>
                     <button className="text-white bg-indigo-600 dark:bg-indigo-500 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase shadow-lg hover:bg-indigo-700 dark:hover:bg-indigo-400 transition-all">Download {state.platform}</button>
                  </div>
                  <div className="flex-1 p-8 space-y-10">
                     {state.rooms.map(room => {
                        const roomItems = state.lineItems.filter(li => li.roomName === room.name);
                        if (roomItems.length === 0) return null;
                        return (
                          <div key={room.id} className="animate-in fade-in slide-in-from-left-4 duration-700">
                             <div className="flex items-center gap-3 mb-6"><div className="h-5 w-1.5 bg-indigo-500 dark:bg-indigo-400 rounded-full"></div><h3 className="font-black text-slate-800 dark:text-slate-200 text-sm uppercase tracking-widest">{room.name}</h3></div>
                             <div className="grid gap-4">
                                {roomItems.map(item => (
                                  <div key={item.id} className="p-6 border border-slate-50 dark:border-slate-800 rounded-3xl bg-slate-50/30 dark:bg-slate-800/10 hover:bg-white dark:hover:bg-slate-800 transition-all group">
                                     <div className="flex items-start justify-between gap-6 mb-4">
                                        <div className="flex items-center gap-3"><span className="font-mono text-[10px] font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1 rounded-lg border border-indigo-100 dark:border-indigo-900/30 tracking-tighter">{item.code}</span><span className="font-black text-slate-900 dark:text-slate-100">{item.description}</span></div>
                                        <div className="text-right shrink-0"><p className="text-lg font-black text-indigo-600 dark:text-indigo-400 tracking-tighter">{item.quantity} {item.unit}</p></div>
                                     </div>
                                     <div className="flex items-start gap-4 text-slate-500 dark:text-slate-400 bg-white dark:bg-slate-900/50 p-4 rounded-2xl border border-slate-50 dark:border-slate-800 text-[11px] leading-relaxed shadow-sm"><Info size={16} className="mt-0.5 shrink-0 text-indigo-300 dark:text-slate-600" /><span><strong className="text-indigo-600 dark:text-indigo-400 uppercase text-[9px] font-black mr-1">Justification:</strong> {item.justification}</span></div>
                                  </div>
                                ))}
                             </div>
                          </div>
                        );
                     })}
                  </div>
               </div>
            </div>
          </div>
          <div className="flex justify-center pt-10 pb-20"><button onClick={() => window.location.reload()} className="px-16 py-6 bg-slate-900 dark:bg-slate-800 text-white rounded-3xl font-black text-xs uppercase tracking-widest hover:bg-black dark:hover:bg-slate-700 transition-all shadow-2xl active:scale-95">Start New Investigation</button></div>
        </div>
      );
    }
    return null;
  };

  const renderMainContent = () => {
    switch(state.mode) {
      case AppMode.DASHBOARD: return renderDashboard();
      case AppMode.INVESTIGATION: return renderInvestigationFlow();
      case AppMode.COMPARISON: return renderComparisonFlow();
      case AppMode.SETTINGS: return renderSettings();
      default: return renderDashboard();
    }
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      {/* Universal Header */}
      <header className="flex flex-col md:flex-row items-center justify-between mb-12 pb-6 border-b border-slate-200 dark:border-slate-800 gap-6">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => handleModeToggle(AppMode.DASHBOARD)}>
          <div className="bg-indigo-600 dark:bg-indigo-50 p-2 rounded-2xl text-white shadow-xl shadow-indigo-200 dark:shadow-none"><ClipboardCheck size={32} /></div>
          <div>
            <h1 className="text-2xl font-black text-slate-900 dark:text-slate-100 tracking-tight leading-none">AdjusterAI</h1>
            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-[0.2em] mt-1.5">Enterprise Estimating Suite</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <nav className="flex bg-slate-200/50 dark:bg-slate-800/50 p-1.5 rounded-2xl shadow-inner backdrop-blur-sm">
            <button 
              onClick={() => handleModeToggle(AppMode.DASHBOARD)} 
              className={`p-2.5 rounded-xl text-xs font-black transition-all ${state.mode === AppMode.DASHBOARD ? 'bg-white dark:bg-slate-900 shadow-lg text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              title="Home Dashboard"
            >
              <Home size={18} />
            </button>
            <button 
              onClick={() => handleModeToggle(AppMode.INVESTIGATION)} 
              className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${state.mode === AppMode.INVESTIGATION ? 'bg-white dark:bg-slate-900 shadow-lg text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
            >
              Investigation
            </button>
            <button 
              onClick={() => handleModeToggle(AppMode.COMPARISON)} 
              className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${state.mode === AppMode.COMPARISON ? 'bg-white dark:bg-slate-900 shadow-lg text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
            >
              Comparison
            </button>
          </nav>

          <button 
            onClick={() => handleModeToggle(AppMode.SETTINGS)} 
            className={`p-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-800 transition-all ${state.mode === AppMode.SETTINGS ? 'text-indigo-600 dark:text-indigo-400 border-indigo-200' : 'text-slate-600 dark:text-slate-400'}`}
          >
            <SettingsIcon size={20} />
          </button>
        </div>

        <div className="hidden lg:flex items-center gap-6">
           <div className="flex items-center gap-2"><Zap size={14} className="text-amber-500 fill-amber-500" /><span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Gemini 3.0 Pro</span></div>
           <div className="h-4 w-px bg-slate-200 dark:bg-slate-800"></div>
           <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Build 2.8.1</span>
        </div>
      </header>

      <main className="min-h-[600px]">
        {renderMainContent()}
      </main>

      {/* Camera Capture Modal */}
      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-black/90 flex flex-col items-center justify-center p-4">
          <div className="relative w-full max-w-2xl bg-slate-900 rounded-3xl overflow-hidden shadow-2xl border border-white/10">
            <video ref={videoRef} autoPlay playsInline className="w-full aspect-[4/3] object-cover" />
            <canvas ref={canvasRef} className="hidden" />

            <div className="p-6 flex items-center justify-between bg-slate-800">
               <button onClick={stopCamera} className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all"><X size={24} /></button>
               <button onClick={capturePhoto} className="group relative">
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center transition-all group-active:scale-90 group-hover:scale-110">
                    <div className="w-14 h-14 border-4 border-slate-800 rounded-full" />
                  </div>
               </button>
               <div className="w-12 h-12" /> {/* Spacer */}
            </div>

            <div className="absolute top-4 left-4 bg-black/50 backdrop-blur-md px-4 py-2 rounded-full flex items-center gap-2 border border-white/10">
               <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse" />
               <span className="text-[10px] font-black text-white uppercase tracking-widest">Live: {state.rooms.find(r => r.id === cameraRoomId)?.name || 'General'}</span>
            </div>
          </div>
        </div>
      )}

      <footer className="mt-20 pt-10 border-t border-slate-200 dark:border-slate-800 text-center space-y-3 pb-12">
        <p className="text-xs text-slate-400 dark:text-slate-500 font-medium tracking-tight">© 2024 AdjusterAI. Forensic Estimating Intelligence.</p>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @keyframes fade-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-in { animation: fade-in 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

