            >
              {state.isAnalyzing ? <><Loader2 className="animate-spin" size={20} /> Mapping Variances...</> : <><Zap size={20} className="fill-white" /> Perform Cross-Platform Audit</>}
            </button>
          </div>
        </div>
      );
    }

    if (step === 3 && state.comparisonResult) {
      const res = state.comparisonResult;
      return (
        <div className="space-y-8 animate-in fade-in duration-700 max-w-6xl mx-auto">
          <div className="grid md:grid-cols-4 gap-6">
             <div className="md:col-span-2 bg-slate-900 dark:bg-slate-800 text-white p-8 rounded-3xl shadow-2xl flex flex-col justify-between">
                <div>
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Executive Variance Analysis</h3>
                  <div className="flex items-center gap-8">
                    <div>
                      <p className="text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-tighter">Est A Total</p>
                      <p className="text-3xl font-black">${res.summary.total.a.toLocaleString()}</p>
                    </div>
                    <ArrowRightLeft className="text-indigo-400" />
                    <div>
                      <p className="text-[10px] font-bold text-slate-500 uppercase mb-1 tracking-tighter">Est B Total</p>
                      <p className="text-3xl font-black">${res.summary.total.b.toLocaleString()}</p>
                    </div>
                  </div>
                </div>
                <div className={`mt-8 px-5 py-3 rounded-2xl font-black text-xl flex items-center justify-between ${res.summary.total.b - res.summary.total.a < 0 ? 'bg-red-500/20 text-red-400' : 'bg-green-500/20 text-green-400'}`}>
                   <span>Net Variance</span>
                   <span>{res.summary.total.b - res.summary.total.a > 0 ? '+' : ''}{(res.summary.total.b - res.summary.total.a).toLocaleString()}</span>
                </div>
             </div>
             <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col justify-between">
                <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Labor Delta</p>
                <div className="space-y-2">
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>A:</span><span>${res.summary.labor.a.toLocaleString()}</span></div>
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>B:</span><span>${res.summary.labor.b.toLocaleString()}</span></div>
                   <div className={`pt-2 border-t dark:border-slate-800 font-black text-lg ${res.summary.labor.b - res.summary.labor.a < 0 ? 'text-red-500' : 'text-green-500'}`}>{res.summary.labor.b - res.summary.labor.a > 0 ? '+' : ''}{(res.summary.labor.b - res.summary.labor.a).toLocaleString()}</div>
                </div>
             </div>
             <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col justify-between">
                <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Material Delta</p>
                <div className="space-y-2">
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>A:</span><span>${res.summary.material.a.toLocaleString()}</span></div>
                   <div className="flex justify-between text-xs font-bold text-slate-500 dark:text-slate-400"><span>B:</span><span>${res.summary.material.b.toLocaleString()}</span></div>
                   <div className={`pt-2 border-t dark:border-slate-800 font-black text-lg ${res.summary.material.b - res.summary.material.a < 0 ? 'text-red-500' : 'text-green-500'}`}>{res.summary.material.b - res.summary.material.a > 0 ? '+' : ''}{(res.summary.material.b - res.summary.material.a).toLocaleString()}</div>
                </div>
             </div>
          </div>
          <div className="grid lg:grid-cols-3 gap-8">
             <div className="lg:col-span-1 space-y-6">
                <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-lg">
                   <h3 className="text-xs font-black text-indigo-500 dark:text-indigo-400 uppercase tracking-widest mb-4 flex items-center gap-2"><ShieldCheck size={16}/> Professional Opinion</h3>
                   <div className="prose prose-slate dark:prose-invert prose-sm font-medium leading-relaxed text-slate-700 dark:text-slate-300 italic">"{res.narrative}"</div>
                </div>
             </div>
             <div className="lg:col-span-2">
                <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden">
                   <div className="p-8 border-b border-slate-50 dark:border-slate-800 flex justify-between items-center bg-slate-50/30 dark:bg-slate-800/20">
                      <h3 className="text-sm font-black text-slate-800 dark:text-slate-200 uppercase tracking-widest flex items-center gap-2"><TrendingDown className="text-indigo-600 dark:text-indigo-400" size={18}/> Variance Grid</h3>
                   </div>
                   <div className="overflow-x-auto">
                      <table className="w-full text-left text-sm border-collapse">
                        <thead className="bg-slate-50/50 dark:bg-slate-800/50 text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest text-[10px]">
                          <tr>
                            <th className="px-8 py-5">Category</th>
                            <th className="px-8 py-5">Mapping</th>
                            <th className="px-8 py-5 text-right">Delta</th>
                            <th className="px-8 py-5">Analysis</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                          {res.variances.map((v, i) => (
                            <tr key={i} className="hover:bg-indigo-50/30 dark:hover:bg-indigo-900/10 transition-all group">
                              <td className="px-8 py-6 align-top"><span className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-lg text-[9px] font-black text-slate-500 dark:text-slate-400 uppercase">{v.category}</span></td>
                              <td className="px-8 py-6 align-top">
                                <div className="space-y-1">
                                  <p className="text-xs font-black text-slate-900 dark:text-slate-100 line-clamp-1">{v.itemA || <span className="text-slate-200 dark:text-slate-700">Missing</span>}</p>
                                  <ArrowRightLeft size={10} className="text-slate-300 dark:text-slate-600" />
                                  <p className="text-xs font-black text-slate-900 dark:text-slate-100 line-clamp-1">{v.itemB || <span className="text-slate-200 dark:text-slate-700">Missing</span>}</p>
                                </div>
                              </td>
                              <td className={`px-8 py-6 text-right font-black align-top text-base ${v.delta < 0 ? 'text-red-500' : 'text-green-500'}`}>{v.delta > 0 ? '+' : ''}{v.delta.toLocaleString()}</td>
                              <td className="px-8 py-6 text-[11px] text-slate-500 dark:text-slate-400 italic leading-relaxed font-medium align-top">{v.reason}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                   </div>
                </div>
                <div className="mt-8 flex justify-center">
                   <button onClick={() => window.location.reload()} className="px-10 py-4 bg-slate-900 dark:bg-slate-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:-translate-y-1 transition-all">New Comparison</button>
                </div>
             </div>
          </div>
        </div>
      );
    }
    return null;
  };

  const renderInvestigationFlow = () => {
    if (step === 1) {
      return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl shadow-slate-200/50 dark:shadow-none border border-slate-200 dark:border-slate-800 p-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-black flex items-center gap-2 text-slate-800 dark:text-slate-100">
              <Building2 className="text-indigo-600 dark:text-indigo-400" /> Claim Investigation Details
            </h2>
            {fetchedGuidelines && (
              <button 
                onClick={saveCurrentGuideline}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-100 transition-all"
              >
                <Save size={14} /> Save Specs to Library
              </button>
            )}
          </div>

          <div className="grid md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <div className="relative" ref={dropdownRef}>
                <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Insurance Carrier</label>
                <div onClick={() => setIsCarrierDropdownOpen(!isCarrierDropdownOpen)} className="flex items-center justify-between px-5 py-3 border border-slate-200 dark:border-slate-700 rounded-2xl bg-slate-50/50 dark:bg-slate-800/50 cursor-pointer hover:border-indigo-500 dark:hover:border-indigo-400 hover:bg-white dark:hover:bg-slate-800 transition-all shadow-sm">
                  <span className={state.carrier ? "text-slate-900 dark:text-slate-100 font-bold" : "text-slate-400 dark:text-slate-500"}>{state.carrier || "Select Carrier..."}</span>
                  <ChevronDown className={`text-slate-400 dark:text-slate-500 transition-transform ${isCarrierDropdownOpen ? 'rotate-180' : ''}`} size={18} />
                </div>
                {isCarrierDropdownOpen && (
                  <div className="absolute z-50 w-full mt-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden">
                    <div className="p-3 border-b dark:border-slate-800">
                      <input 
                        autoFocus 
                        type="text" 
                        placeholder="Type carrier name..." 
                        className="w-full px-4 py-2 text-sm bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-slate-100 rounded-xl outline-none" 
                        value={state.carrier} 
                        onChange={e => setState(p => ({ ...p, carrier: e.target.value }))} 
                        onKeyDown={(e) => e.key === 'Enter' && selectCarrier(state.carrier)}
                      />
                    </div>
                    <div className="max-h-64 overflow-y-auto p-2">
                       {carrierFavorites.length > 0 && (
                         <div className="mb-2">
                            <p className="px-3 py-1 text-[9px] font-black text-slate-400 uppercase tracking-widest">Favorites</p>
                            {carrierFavorites.map(fav => (
                              <div key={fav} className="group flex items-center justify-between px-3 py-2 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-xl cursor-pointer" onClick={() => selectCarrier(fav)}>
                                <div className="flex items-center gap-3"><Star className="text-amber-400 fill-amber-400" size={12} /><span className="text-sm font-bold text-slate-700 dark:text-slate-200">{fav}</span></div>
                              </div>
                            ))}
                         </div>
                       )}
                       <div>
                         <p className="px-3 py-1 text-[9px] font-black text-slate-400 uppercase tracking-widest">Recent</p>
                         {carrierHistory.map(hist => (
                          <div key={hist} className="group flex items-center justify-between px-3 py-2 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl cursor-pointer" onClick={() => selectCarrier(hist)}>
                            <div className="flex items-center gap-3 text-slate-500 dark:text-slate-400"><History size={12} /><span className="text-sm font-medium">{hist}</span></div>
                            <button onClick={(e) => toggleFavorite(e, hist)} className="opacity-0 group-hover:opacity-100 p-1"><Star size={12} className="text-slate-300" /></button>
                          </div>
                         ))}
                       </div>
                    </div>
                  </div>
                )}
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Estimating Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  {Object.values(Platform).map(p => (
                    <button key={p} onClick={() => setState(prev => ({ ...prev, platform: p }))} className={`py-4 rounded-2xl border-2 font-black text-xs uppercase tracking-widest transition-all ${state.platform === p ? 'border-indigo-600 dark:border-indigo-400 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 shadow-md' : 'border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-400 dark:text-slate-500 hover:border-slate-200 dark:hover:border-slate-700'}`}>{p}</button>
                  ))}
                </div>
              </div>

              {fetchedGuidelines && (
                <div className="p-6 bg-slate-50 dark:bg-slate-800/30 rounded-3xl border border-slate-100 dark:border-slate-800 space-y-3">
                  <h4 className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest flex items-center gap-2"><ShieldCheck size={14}/> Active Guidelines</h4>
                  <div className="text-[11px] text-slate-600 dark:text-slate-400 leading-relaxed max-h-40 overflow-y-auto custom-scrollbar italic whitespace-pre-wrap">
                    {fetchedGuidelines}
                  </div>
                </div>
              )}
              {guidelinesLoading && (
                <div className="flex items-center gap-3 p-6 bg-indigo-50 dark:bg-indigo-900/10 rounded-3xl border border-indigo-100 dark:border-indigo-900/20 text-indigo-600 dark:text-indigo-400">
                   <Loader2 className="animate-spin" size={20} />
                   <p className="text-[10px] font-black uppercase tracking-widest">Consulting Search Grounding...</p>
                </div>
              )}
            </div>
            <div className="space-y-4">
              <label className="block text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-2">Claim Scope Synopsis</label>
              <textarea rows={14} placeholder="Detailed damage narrative..." className="w-full px-6 py-4 border border-slate-200 dark:border-slate-700 rounded-3xl outline-none bg-slate-50/50 dark:bg-slate-800/50 hover:bg-white dark:hover:bg-slate-800 text-slate-900 dark:text-slate-100 transition-all text-sm font-medium" value={state.synopsis} onChange={e => setState(p => ({ ...p, synopsis: e.target.value }))} />
              {(state.synopsis?.length || 0) > 100 && (
                <div className="flex items-center gap-2 px-4 py-2 bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-green-100 dark:border-green-900/30">
                  <CheckCircle2 size={14} /> Synopsis corrobation enabled
                </div>
              )}
            </div>
          </div>
          <div className="mt-10 flex justify-end">
            <button onClick={() => setStep(2)} className="bg-slate-900 dark:bg-slate-800 hover:bg-black dark:hover:bg-slate-700 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 transition-all shadow-xl">Next: Structural Zones <ChevronRight size={18} /></button>
          </div>
        </div>
      );
    }

    if (step === 2) {
      return (
        <div className="space-y-8 animate-in fade-in max-w-7xl mx-auto relative">
          {/* Header Section */}
          <div className="flex items-center justify-between px-2 flex-wrap gap-4">
            <h2 className="text-2xl font-black flex items-center gap-3 text-slate-800 dark:text-slate-100">
              <LayoutGrid className="text-indigo-600 dark:text-indigo-400" size={28} />
              Structural Zone Scoping
            </h2>

            {/* Switch-style Zone Selector: Interior vs Exterior only */}
            <nav className="flex bg-slate-200/50 dark:bg-slate-800/50 p-1.5 rounded-2xl shadow-inner backdrop-blur-sm">
              <button 
                onClick={() => { setActiveZoneType('Interior'); setRoomSearch(''); setShowElevationSelector(false); }}
                className={`px-8 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeZoneType === 'Interior' ? 'bg-white dark:bg-slate-900 shadow-lg text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              >
                <Building2 size={14} />
                Interior
              </button>
              <button 
                onClick={() => { setActiveZoneType('Exterior'); setRoomSearch(''); setShowElevationSelector(false); }}
                className={`px-8 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeZoneType === 'Exterior' ? 'bg-white dark:bg-slate-900 shadow-lg text-amber-600 dark:text-amber-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              >
                <Sun size={14} />
                Exterior
              </button>
            </nav>
          </div>

          <div className="grid lg:grid-cols-12 gap-8 items-start">
            {/* Left Column: Room Selection List */}
            <div className="lg:col-span-4 space-y-4 h-full relative">
               <div className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 p-6 shadow-sm flex flex-col h-[600px] relative">
                  <div className="mb-4">
                    <h3 className={`text-xs font-black uppercase tracking-widest mb-4 flex items-center gap-2 ${activeZoneType === 'Interior' ? 'text-indigo-600 dark:text-indigo-400' : 'text-amber-600 dark:text-amber-400'}`}>
                      {activeZoneType === 'Interior' ? <Building2 size={16}/> : <Camera size={16}/>}
                      Available {activeZoneType} Zones
                    </h3>
                    <div className="relative">
                      <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                      <input 
                        type="text" 
                        placeholder={`Search ${activeZoneType.toLowerCase()} types...`} 
                        className="w-full pl-11 pr-4 py-3 bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 rounded-xl text-sm font-medium focus:ring-2 focus:ring-indigo-500/20 outline-none"
                        value={roomSearch}
                        onChange={(e) => setRoomSearch(e.target.value)}
                      />
                    </div>
                  </div>

                  <div className="flex-1 overflow-y-auto custom-scrollbar space-y-1 pr-2">
                    {filteredRoomTypes.length > 0 ? (
                      filteredRoomTypes.map(roomType => (
                        <div key={roomType} className="flex items-center gap-1 group">
                          {activeZoneType === 'Interior' && (
                            <button 
                              onClick={(e) => toggleRoomFavorite(e, roomType)}
                              className={`p-2 transition-colors ${roomFavorites.includes(roomType) ? 'text-amber-400' : 'text-slate-300 hover:text-slate-400'}`}
                            >
                              <Star size={16} fill={roomFavorites.includes(roomType) ? "currentColor" : "none"} />
                            </button>
                          )}
                          <button 
                            onClick={() => {
                              if (activeZoneType === 'Exterior' && roomType === 'Elevation') {
                                setShowElevationSelector(true);
                              } else {
                                addRoom(roomType, activeZoneType === 'Interior' ? 'Room' : 'Exterior Face');
                              }
                            }}
                            className="flex-1 text-left px-4 py-3 rounded-xl hover:bg-indigo-50 dark:hover:bg-indigo-900/20 text-slate-700 dark:text-slate-300 font-bold text-sm transition-all flex items-center justify-between border border-transparent hover:border-indigo-100 dark:hover:border-indigo-800"
                          >
                            <span className="truncate">{roomType}</span>
                            <Plus size={14} className="text-slate-300 group-hover:text-indigo-500 opacity-0 group-hover:opacity-100 transition-all" />
                          </button>
                        </div>
                      ))
                    ) : (
                      <div className="py-10 text-center space-y-2 opacity-40">
                        <Search size={24} className="mx-auto" />
                        <p className="text-xs font-bold uppercase tracking-tighter">No types match "{roomSearch}"</p>
                      </div>
                    )}
                  </div>

                  <div className="pt-4 border-t dark:border-slate-800 mt-2">
                    <p className="text-[10px] text-slate-400 font-bold italic text-center">Tip: Select a type multiple times to add duplicate rooms (e.g. Bedroom 2, Bedroom 3)</p>
                  </div>

                  {/* Elevation Sub-selector Overlay */}
                  {showElevationSelector && (
                    <div className="absolute inset-0 z-20 bg-white/95 dark:bg-slate-900/95 rounded-[2rem] p-8 flex flex-col items-center justify-center animate-in fade-in duration-200">
                      <button 
                        onClick={() => setShowElevationSelector(false)}
                        className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                      >
                        <X size={20} />
                      </button>
                      <h4 className="text-sm font-black text-amber-600 uppercase tracking-widest mb-8">Select Elevation Direction</h4>
                      <div className="grid grid-cols-2 gap-4 w-full">
