        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @keyframes fade-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-in { animation: fade-in 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

export enum Platform {
  XACTIMATE = 'Xactimate',
  SYMBILITY_COTALITY = 'Symbility / Cotality'
}

export enum AppMode {
  DASHBOARD = 'Dashboard',
  INVESTIGATION = 'Investigation',
  COMPARISON = 'Comparison',
  SETTINGS = 'Settings',
  REPORTS = 'Reports'
}

export type DamageCategory = 'Water' | 'Fire' | 'Structural' | 'Cosmetic' | 'Mold/Microbial' | 'Unknown';

export type EvidenceType = 'Photo' | 'PDF Package' | 'Scope Sheet' | 'Measurement Report' | 'Technical Document' | 'Estimate File';

export interface Room {
  id: string;
  name: string;
  type: 'Room' | 'Exterior Face';
}

export interface EvidenceItem {
  id: string;
  roomId?: string;
  type: EvidenceType;
  base64: string;
  mimeType: string;
  fileName: string;
  label?: string;
  detectedDamage?: {
    category: DamageCategory;
    confidence: number;
    observations: string;
  };
}

export interface LineItem {
  id: string;
  code: string;
  description: string;
  quantity: number;
  unit: string;
  roomName: string;
  justification?: string;
}

export interface VarianceDetail {
  category: string;
  itemA: string;
  itemB: string;
  delta: number;
  reason: string;
}

export interface ComparisonSummary {
  labor: { a: number; b: number };
  material: { a: number; b: number };
  total: { a: number; b: number };
}

export interface ComparisonResult {
  summary: ComparisonSummary;
  variances: VarianceDetail[];
  narrative: string;
}

export interface SavedReport {
  id: string;
  type: 'Investigation' | 'Comparison';
  title: string;
  carrier: string;
  timestamp: number;
  platform: string;
  state: any;
}

export interface EstimationState {
  mode: AppMode;
  carrier: string;
  synopsis: string;
  platform: Platform;
  rooms: Room[];
  evidence: EvidenceItem[];
  lineItems: LineItem[];
  isAnalyzing: boolean;
  analysisComplete: boolean;
  customGuidelines?: string;
  uploadedGuidelineName?: string;

  // Comparison specific
  fileA?: EvidenceItem;
  fileB?: EvidenceItem;
  platformA: Platform;
  platformB: Platform;
  comparisonResult?: ComparisonResult;
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Building2, 
  ClipboardCheck, 
  Camera, 
  FileText, 
  ChevronRight, 
  Plus, 
  Trash2, 
  Loader2, 
  CheckCircle2, 
