import { GoogleGenAI, Type } from "@google/genai";
import { Platform, EvidenceItem, LineItem, DamageCategory, ComparisonResult } from "../types";

// Always use the API_KEY from process.env directly.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchCarrierGuidelines = async (carrier: string): Promise<string> => {
  const prompt = `Find the 2024-2025 property estimating and repair guidelines for the insurance carrier: ${carrier}. 
  Summarize key rules for material waste, overhead and profit, and mandatory line items.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { 
        tools: [{ googleSearch: {} }],
        // Use systemInstruction for defining the persona.
        systemInstruction: "You are an expert insurance industry researcher specializing in property claim guidelines.",
      },
    });

    // Extract grounding chunks and list them as required by instructions.
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    let sourceLinks = "";
    if (groundingChunks && groundingChunks.length > 0) {
      const links = groundingChunks
        .map((chunk: any) => chunk.web ? `[${chunk.web.title}](${chunk.web.uri})` : null)
        .filter(Boolean);
      if (links.length > 0) {
        sourceLinks = "\n\nSources:\n" + links.join("\n");
      }
    }

    // Access response.text directly (not a function).
    return (response.text || "No specific guidelines found.") + sourceLinks;
  } catch (error) {
    console.error("fetchCarrierGuidelines error:", error);
    return "Error retrieving carrier guidelines.";
  }
};

export const analyzeDamage = async (
  platform: Platform,
  carrier: string,
  synopsis: string,
  guidelines: string,
  evidence: EvidenceItem[],
  rooms: { [id: string]: string }
): Promise<{ lineItems: LineItem[]; labeledEvidence: EvidenceItem[] }> => {
  const mediaParts = evidence.map(item => ({
    inlineData: { data: item.base64.split(',')[1] || item.base64, mimeType: item.mimeType }
  }));

  const prompt = `Target Platform: ${platform}. 
    Insurance Carrier: ${carrier}.
    Carrier Guidelines: ${guidelines}
    Site Synopsis: ${synopsis}

    TASK:
    Analyze the provided site data. 
    NOTE: If photos are limited or missing, prioritize the Detailed Synopsis and Technical Documents (like Measurement Reports/Eagleviews). 
    If the synopsis contains a component list or detailed measurements for a roofing claim, generate the full estimate based on those specs even without photographic corroboration for every item.

    1. Extract measurements and damage evidence from all sources.
    2. Categorize damage type (Water, Fire, Structural, Roofing, etc.).
    3. Generate highly accurate ${platform} line items with justification.
    4. Provide professional labels for any available evidence.

    Output valid JSON with "lineItems" and "evidenceResults".`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts: [...mediaParts, { text: prompt }] },
    config: {
      // Define persona in systemInstruction.
      systemInstruction: "You are an expert Forensic Insurance Adjuster and Estimator.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lineItems: { 
            type: Type.ARRAY, 
            items: { 
              type: Type.OBJECT, 
              properties: { 
                code: { type: Type.STRING }, 
                description: { type: Type.STRING }, 
                quantity: { type: Type.NUMBER }, 
                unit: { type: Type.STRING }, 
                roomName: { type: Type.STRING }, 
                justification: { type: Type.STRING } 
              }, 
              required: ["code", "description", "quantity", "unit", "roomName", "justification"] 
            } 
          },
          evidenceResults: { 
            type: Type.ARRAY, 
            items: { 
              type: Type.OBJECT, 
              properties: { 
                id: { type: Type.STRING }, 
                label: { type: Type.STRING }, 
                damageCategory: { type: Type.STRING }, 
                confidence: { type: Type.NUMBER }, 
                observations: { type: Type.STRING } 
              }, 
              required: ["id", "label"] 
            } 
          }
        }
      }
    }
  });

  // Access response.text directly.
  const result = JSON.parse(response.text || '{}');
  return {
    lineItems: result.lineItems.map((li: any, index: number) => ({ ...li, id: `li-${index}` })),
    labeledEvidence: evidence.map(e => {
      const match = result.evidenceResults?.find((res: any) => res.id === e.id);
      return { 
        ...e, 
        label: match?.label || "Site Evidence", 
        detectedDamage: match?.damageCategory ? { 
          category: match.damageCategory as DamageCategory, 
          confidence: match.confidence || 0, 
          observations: match.observations || "Evidence reviewed." 
        } : undefined 
      };
    })
  };
};

export const compareEstimates = async (
  fileA: EvidenceItem,
  fileB: EvidenceItem,
  platformA: Platform,
  platformB: Platform
): Promise<ComparisonResult> => {
  const prompt = `
    Compare these two repair estimates for a property claim:
    Estimate A (${platformA}): From file "${fileA.fileName}"
    Estimate B (${platformB}): From file "${fileB.fileName}"

    STRICT INSTRUCTIONS:
    1. Mapping: Align equivalent line items even if codes differ (e.g. Xactimate "DRY 1/2" vs Symbility equivalent).
    2. Parsing: Extract line items, quantities, and prices from the documents (XML, CSV, or OCR text).
    3. Financial Summary: Calculate total Labor, Material, and Grand Totals for both.
    4. Variance Analysis: 
       - Identify missing items in either estimate.
       - Note quantity mismatches (over/under scoping).
       - Detect labor rate inflation or material bundling differences.
    5. Narrative Summary: Write a professional narrative explaining WHY the total variance exists.

    Output valid JSON matching this schema:
    {
      "summary": {
        "labor": { "a": number, "b": number },
        "material": { "a": number, "b": number },
        "total": { "a": number, "b": number }
      },
      "variances": [
        { "category": "Labor|Material|Scope|Admin", "itemA": "string", "itemB": "string", "delta": number, "reason": "string" }
      ],
      "narrative": "string"
    }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: {
      parts: [
        { inlineData: { data: fileA.base64.split(',')[1], mimeType: fileA.mimeType } },
        { inlineData: { data: fileB.base64.split(',')[1], mimeType: fileB.mimeType } },
        { text: prompt }
      ]
    },
    config: {
      // Use systemInstruction for persona.
      systemInstruction: "You are an expert Forensic Auditor specializing in insurance estimate reconciliation.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { 
            type: Type.OBJECT, 
            properties: { 
              labor: { type: Type.OBJECT, properties: { a: { type: Type.NUMBER }, b: { type: Type.NUMBER } } }, 
              material: { type: Type.OBJECT, properties: { a: { type: Type.NUMBER }, b: { type: Type.NUMBER } } }, 
              total: { type: Type.OBJECT, properties: { a: { type: Type.NUMBER }, b: { type: Type.NUMBER } } } 
            } 
          },
          variances: { 
            type: Type.ARRAY, 
            items: { 
              type: Type.OBJECT, 
              properties: { 
                category: { type: Type.STRING }, 
                itemA: { type: Type.STRING }, 
                itemB: { type: Type.STRING }, 
                delta: { type: Type.NUMBER }, 
                reason: { type: Type.STRING } 
              } 
            } 
          },
          narrative: { type: Type.STRING }
        }
      }
    }
  });

  // Access response.text directly.
  return JSON.parse(response.text || '{}') as ComparisonResult;
};

