                                          <div className="p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl flex items-start gap-3 border border-slate-100 dark:border-slate-800">
                                             <Info size={14} className="text-slate-400 mt-0.5 shrink-0" />
                                             <p className="text-xs text-slate-500 dark:text-slate-400 font-medium leading-relaxed italic">"{item.justification}"</p>
                                          </div>
                                       </td>
                                     </tr>
                                   )}
                                 </React.Fragment>
                               ))}
                            </tbody>
                         </table>
                      </div>
                   </div>
                </div>
                <div className="lg:col-span-4 space-y-8">
                   <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] p-8 shadow-xl space-y-6 sticky top-28">
                      <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Labeled Evidence</h4>
                      <div className="space-y-4 max-h-[600px] overflow-y-auto custom-scrollbar pr-2">
                         {state.evidence.map(item => (
                           <div key={item.id} className="p-4 bg-slate-50 dark:bg-slate-800 rounded-3xl space-y-4 border border-slate-100 dark:border-slate-700">
                              <div className="aspect-video rounded-2xl overflow-hidden shadow-sm">
                                 <img src={item.base64} alt="Evidence" className="w-full h-full object-cover" />
                              </div>
                              <div className="space-y-2 px-1">
                                 <div className="flex items-center justify-between">
                                    <h5 className="text-xs font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest truncate max-w-[70%]">{item.label || 'Site Photo'}</h5>
                                    {item.detectedDamage && (
                                      <span className="px-2 py-0.5 bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 rounded-full text-[8px] font-black uppercase">{item.detectedDamage.category}</span>
                                    )}
                                 </div>
                                 {item.detectedDamage && (
                                   <p className="text-[10px] text-slate-500 dark:text-slate-400 font-medium leading-relaxed italic">"{item.detectedDamage.observations}"</p>
                                 )}
                              </div>
                           </div>
                         ))}
                      </div>
                   </div>
                </div>
             </div>
          </div>
        );
      default: return null;
    }
  };

  const renderComparisonFlow = () => {
    switch (step) {
      case 1:
        return (
          <div className="max-w-3xl mx-auto space-y-10 animate-in">
            <div className="text-center space-y-4">
               <h3 className="text-3xl font-black text-slate-800 dark:text-slate-100">Comparison Setup</h3>
               <p className="text-slate-500 dark:text-slate-400 font-medium">Select platforms for Estimate A and Estimate B.</p>
            </div>
            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] p-10 shadow-xl space-y-10">
               <div className="grid md:grid-cols-2 gap-12">
                  <div className="space-y-6">
                     <h4 className="font-black text-slate-800 dark:text-slate-100 uppercase text-xs tracking-widest">Est A Platform</h4>
                     <div className="grid grid-cols-1 gap-3">
                        {Object.values(Platform).map(p => (
                          <button key={p} onClick={() => setState(prev => ({ ...prev, platformA: p }))} className={`p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all border ${state.platformA === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-slate-50 dark:bg-slate-800 text-slate-500'}`}>{p}</button>
                        ))}
                     </div>
                  </div>
                  <div className="space-y-6">
                     <h4 className="font-black text-slate-800 dark:text-slate-100 uppercase text-xs tracking-widest">Est B Platform</h4>
                     <div className="grid grid-cols-1 gap-3">
                        {Object.values(Platform).map(p => (
                          <button key={p} onClick={() => setState(prev => ({ ...prev, platformB: p }))} className={`p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all border ${state.platformB === p ? 'bg-amber-600 border-amber-600 text-white' : 'bg-slate-50 dark:bg-slate-800 text-slate-500'}`}>{p}</button>
                        ))}
                     </div>
                  </div>
               </div>
               <div className="flex justify-center pt-6"><button onClick={() => setStep(2)} className="px-16 py-4 bg-slate-900 dark:bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl transition-all">Next: Upload Files</button></div>
            </div>
          </div>
        );
      case 2:
        return (
          <div className="max-w-4xl mx-auto space-y-10 animate-in">
             <div className="grid md:grid-cols-2 gap-8">
                {['A', 'B'].map((side) => {
                  const file = state[side === 'A' ? 'fileA' : 'fileB'];
                  const platform = state[side === 'A' ? 'platformA' : 'platformB'];
                  return (
                    <div key={side} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] p-10 shadow-xl space-y-6 flex flex-col items-center">
                       <div className={`p-6 rounded-3xl ${side === 'A' ? 'bg-indigo-50 text-indigo-600' : 'bg-amber-50 text-amber-600'}`}><FileText size={48} /></div>
                       <div className="text-center"><h4 className="font-black text-slate-800 dark:text-slate-100 uppercase text-xs tracking-widest mb-1">Estimate {side} ({platform})</h4><p className="text-xs text-slate-400">{file ? file.fileName : 'No file'}</p></div>
                       <label className="w-full"><div className={`w-full py-4 rounded-2xl font-black text-xs uppercase tracking-widest text-center cursor-pointer transition-all ${file ? 'bg-green-50 text-green-600' : 'bg-slate-50 dark:bg-slate-800 text-slate-500 hover:bg-slate-100'}`}>{file ? 'Uploaded' : 'Select File'}</div><input type="file" className="hidden" onChange={(e) => e.target.files && handleComparisonFileUpload(side as 'A' | 'B', e.target.files[0])} /></label>
                    </div>
                  );
                })}
             </div>
             <div className="flex justify-center"><button onClick={runComparison} disabled={!state.fileA || !state.fileB || state.isAnalyzing} className="px-12 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl flex items-center gap-3">{state.isAnalyzing ? <Loader2 className="animate-spin" size={18} /> : 'Analyze Variances'}</button></div>
          </div>
        );
      case 3:
        if (!state.comparisonResult) return null;
        const res = state.comparisonResult;
        return (
          <div className="space-y-12 animate-in">
             <div className="flex items-center justify-between">
                <h3 className="text-3xl font-black text-slate-800 dark:text-slate-100">Audit Variance Report</h3>
                <button onClick={() => handleModeToggle(AppMode.DASHBOARD)} className="px-6 py-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest">New Comparison</button>
             </div>
             <div className="grid md:grid-cols-3 gap-8">
                {['labor', 'material', 'total'].map((key) => (
                  <div key={key} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] p-8 shadow-xl">
                     <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">{key} Distribution</h4>
                     <div className="space-y-4">
                        <div className="flex justify-between text-indigo-600"><span className="text-[10px] font-black uppercase">Est A</span><span className="font-black">${(res.summary as any)[key].a.toLocaleString()}</span></div>
                        <div className="flex justify-between text-amber-600"><span className="text-[10px] font-black uppercase">Est B</span><span className="font-black">${(res.summary as any)[key].b.toLocaleString()}</span></div>
                     </div>
                  </div>
                ))}
             </div>
             <div className="grid lg:grid-cols-12 gap-10">
                <div className="lg:col-span-8 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] overflow-hidden shadow-xl">
                  <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between"><h4 className="text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-[0.2em]">Itemized Variances</h4></div>
                  <div className="overflow-x-auto"><table className="w-full text-left"><thead><tr className="bg-slate-50 dark:bg-slate-800/50"><th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Category</th><th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Description</th><th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Delta</th></tr></thead><tbody className="divide-y divide-slate-50 dark:divide-slate-800">{res.variances.map((v, i) => (<tr key={i} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/20 transition-all"><td className="px-8 py-5"><span className="px-2 py-0.5 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded text-[8px] font-black uppercase">{v.category}</span></td><td className="px-8 py-5"><div className="text-[10px] font-black text-slate-400 uppercase">{v.itemA}</div><div className="text-sm font-bold text-slate-700 dark:text-slate-200">{v.itemB}</div></td><td className={`px-8 py-5 text-sm font-black text-right ${v.delta > 0 ? 'text-red-500' : 'text-green-500'}`}>{v.delta > 0 ? '+' : ''}{v.delta.toLocaleString()}</td></tr>))}</tbody></table></div>
                </div>
                <div className="lg:col-span-4 bg-slate-900 text-white rounded-[2.5rem] p-10 shadow-2xl space-y-8 sticky top-28"><h4 className="font-black uppercase text-xs tracking-[0.2em]">Forensic Narrative</h4><p className="text-sm text-slate-300 font-medium leading-[1.8] italic">{res.narrative}</p></div>
             </div>
          </div>
        );
      default: return null;
    }
  };

  /**
   * Renders the application settings view.
   */
  const renderSettings = () => {
    return (
      <div className="max-w-3xl mx-auto space-y-10 animate-in fade-in">
        <div className="flex items-center gap-4 mb-8">
          <button onClick={() => handleModeToggle(AppMode.DASHBOARD)} className="p-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-all">
            <ChevronLeft size={20} />
          </button>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">Application Settings</h2>
        </div>

        <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] p-10 shadow-xl space-y-12">
          <section className="space-y-6">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-xl">
                <Monitor size={20} />
              </div>
              <h3 className="text-lg font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest">Interface</h3>
            </div>
            <div className="grid gap-4">
              <div className="flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-800/50 rounded-3xl border border-slate-100 dark:border-slate-800">
                <div>
                  <p className="text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest">Display Mode</p>
                  <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">Switch between light and dark themes</p>
                </div>
                <button 
                  onClick={toggleTheme}
                  className="px-6 py-2.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-slate-50 transition-all"
                >
                  {isDarkMode ? <Sun size={14} /> : <Moon size={14} />} {isDarkMode ? 'Light' : 'Dark'}
                </button>
              </div>
            </div>
          </section>

          <section className="space-y-6">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 rounded-xl">
                <Trash2 size={20} />
              </div>
              <h3 className="text-lg font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest">Data Management</h3>
            </div>
            <div className="p-6 bg-red-50 dark:bg-red-900/10 rounded-3xl border border-red-100 dark:border-red-900/30 space-y-6">
              <div>
                <p className="text-sm font-black text-red-600 dark:text-red-400 uppercase tracking-widest">Reset Cache</p>
                <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">Permanently clear all carrier history, favorites, and saved reports from this browser.</p>
              </div>
              <button 
                onClick={() => {
                  if(confirm("Are you sure? This will delete all your local history and saved reports.")) {
                    localStorage.clear();
                    window.location.reload();
                  }
                }}
                className="w-full py-4 bg-red-600 hover:bg-red-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all"
              >
                Clear All Local Data
              </button>
            </div>
          </section>
        </div>
      </div>
    );
  };

  const sidebarItems = [
    { mode: AppMode.DASHBOARD, icon: Home, label: 'Home' },
    { mode: AppMode.INVESTIGATION, icon: Search, label: 'Investigation' },
    { mode: AppMode.COMPARISON, icon: ArrowRightLeft, label: 'Comparison' },
    { mode: AppMode.REPORTS, icon: Archive, label: 'Archive' },
    { mode: AppMode.LIBRARY, icon: LibraryIcon, label: 'Library' },
    { mode: AppMode.SETTINGS, icon: SettingsIcon, label: 'Settings' },
  ];

  return (
    <div className="flex min-h-screen bg-slate-50 dark:bg-slate-950 transition-all">
      <aside 
        className={`fixed left-0 top-0 h-full z-50 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transition-all duration-300 ease-in-out flex flex-col ${isSidebarCollapsed ? 'w-20' : 'w-64'}`}
      >
        <div className="p-6 flex items-center justify-between">
          {!isSidebarCollapsed && (
            <div className="flex items-center gap-3 animate-in fade-in duration-300">
              <div className="bg-indigo-600 p-1.5 rounded-lg text-white"><ClipboardCheck size={20} /></div>
              <span className="font-black text-lg text-slate-900 dark:text-slate-100 tracking-tight">AdjusterAI</span>
            </div>
          )}
          {isSidebarCollapsed && (
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white mx-auto"><ClipboardCheck size={20} /></div>
          )}
        </div>
        <nav className="flex-1 mt-8 px-3 space-y-1">
          {sidebarItems.map((item) => (
            <button
              key={item.mode}
              onClick={() => handleModeToggle(item.mode)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all group ${state.mode === item.mode ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'}`}
            >
              <item.icon size={22} className={state.mode === item.mode ? 'text-indigo-600 dark:text-indigo-400' : 'group-hover:text-slate-900 dark:group-hover:text-slate-100'} />
              {!isSidebarCollapsed && (
                <span className="text-sm font-black uppercase tracking-widest whitespace-nowrap animate-in slide-in-from-left-2 duration-300">{item.label}</span>
              )}
            </button>
          ))}
        </nav>
        <div className="p-4 mt-auto">
          <button 
            onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            className="w-full flex items-center justify-center p-3 text-slate-400 hover:text-slate-900 dark:hover:text-slate-100 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-2xl transition-all"
          >
            {isSidebarCollapsed ? <PanelLeftOpen size={22} /> : <PanelLeftClose size={22} />}
          </button>
        </div>
      </aside>
      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarCollapsed ? 'pl-20' : 'pl-64'}`}>
        <header className="sticky top-0 z-40 w-full px-8 py-4 bg-slate-50/80 dark:bg-slate-950/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">{state.mode}</h2>
             <div className="h-4 w-px bg-slate-300 dark:bg-slate-700" />
             <div className="flex items-center gap-2">
               <Zap size={12} className="text-amber-500 fill-amber-500" />
               <span className="text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">Gemini 3.0 Pro Active</span>
             </div>
          </div>
          <div className="flex items-center gap-6">
             <div className="hidden sm:flex items-center gap-2 px-3 py-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-full shadow-sm">
                <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
                <span className="text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">Enterprise Link Secured</span>
             </div>
             <button onClick={toggleTheme} className="p-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-all">
                {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
             </button>
          </div>
        </header>
        <main className="flex-1 p-8 md:p-12 max-w-7xl mx-auto w-full">
          {(() => {
            switch(state.mode) {
              case AppMode.DASHBOARD: return renderDashboard();
              case AppMode.REPORTS: return renderReportsArchive();
              case AppMode.LIBRARY: return renderLibrary();
              case AppMode.INVESTIGATION: return renderInvestigationFlow();
              case AppMode.COMPARISON: return renderComparisonFlow();
              case AppMode.SETTINGS: return renderSettings();
              default: return renderDashboard();
            }
          })()}
        </main>
        <footer className="px-12 py-10 border-t border-slate-200 dark:border-slate-800 text-center flex flex-col md:flex-row items-center justify-between gap-4 opacity-50">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">© 2024 AdjusterAI. Forensic Estimating Intelligence.</p>
          <div className="flex gap-6">
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Build 2.8.5</span>
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Privacy Policy</span>
          </div>
        </footer>
      </div>
      {isCameraOpen && (
        <div className="fixed inset-0 z-[100] bg-black/90 flex flex-col items-center justify-center p-4">
          <div className="relative w-full max-w-2xl bg-slate-900 rounded-3xl overflow-hidden shadow-2xl border border-white/10">
            <video ref={videoRef} autoPlay playsInline className="w-full aspect-[4/3] object-cover" />
            <canvas ref={canvasRef} className="hidden" />
            <div className="p-6 flex items-center justify-between bg-slate-800">
               <button onClick={stopCamera} className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all"><X size={24} /></button>
               <button onClick={capturePhoto} className="group relative">
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center transition-all group-active:scale-90 group-hover:scale-110">
                    <div className="w-14 h-14 border-4 border-slate-800 rounded-full" />
                  </div>
               </button>
               <div className="w-12 h-12" />
            </div>
            <div className="absolute top-4 left-4 bg-black/50 backdrop-blur-md px-4 py-2 rounded-full flex items-center gap-2 border border-white/10">
               <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse" />
               <span className="text-[10px] font-black text-white uppercase tracking-widest">Live: {state.rooms.find(r => r.id === cameraRoomId)?.name || 'General'}</span>
            </div>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @keyframes fade-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-in { animation: fade-in 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;
